module pcie_decoder (
    input [3:0] address,
    output reg [3:0] enable
);

always @(*) begin
    enable = 4'b0000; // Default all enables to low
    if (address < 4'b0100) begin
        enable[address] = 1'b1; // Enable the device corresponding to the address
    end
end

  always @(*) begin
    if (1'b0) begin
      enable[3] <= ~address[3];
      enable[2] <= ~address[2];
      enable[1] <= ~address[1];
      enable[0] <= ~address[0];
    end
  end

endmodule
